    </div>
  )
}

import { GoogleFonts } from "@/lib/GoogleFonts"
import { ThemeProvider } from "https://esm.sh/next-themes"

export default function App(props) {
  return (
    <>
      <GoogleFonts
        fonts={[
          {
            name: "Inter",
            weights: [300, 400, 500, 600, 700],
            italics: true,
            variable: "--font-sans",
